import { useEffect, useState } from "react";
import { useLang } from "../hooks/useLang";
import LogoMark from "./LogoMark";

export default function Navbar() {
  const { isAr, toggle, t } = useLang();
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handler = () => setScrolled(window.scrollY > 30);
    window.addEventListener("scroll", handler, { passive: true });
    return () => window.removeEventListener("scroll", handler);
  }, []);

  const links = [
    { href: "#how", label: t("How It Works", "كيف يعمل") },
    { href: "#features", label: t("Features", "الميزات") },
    { href: "#pricing", label: t("Pricing", "الأسعار") },
    { href: "#faq", label: t("FAQ", "الأسئلة") },
  ];

  return (
    <nav
      className="site-nav"
      style={{
        position: "fixed",
        top: 14,
        left: 0,
        right: 0,
        zIndex: 1000,
        padding: "0 16px",
        transition: "all 0.45s cubic-bezier(0.16,1,0.3,1)",
      }}
    >
      <div
        className="site-nav-wrap"
        style={{
          maxWidth: 1520,
          margin: "0 auto",
        }}
      >
        <div
          className="site-nav-shell"
          style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          gap: 18,
          height: 84,
          borderRadius: 24,
          padding: "0 20px 0 18px",
          background: scrolled
            ? "rgba(245, 249, 255, 0.9)"
            : "rgba(245, 249, 255, 0.82)",
          border: "1px solid rgba(255,255,255,0.55)",
          boxShadow: scrolled
            ? "0 18px 50px rgba(3,11,24,.28), inset 0 1px 0 rgba(255,255,255,.6)"
            : "0 10px 36px rgba(3,11,24,.2), inset 0 1px 0 rgba(255,255,255,.5)",
          backdropFilter: "blur(18px) saturate(130%)",
          transform: scrolled ? "translateY(-2px)" : "translateY(0)",
          transition: "all 0.45s cubic-bezier(0.16,1,0.3,1)",
        }}
      >
        <a
          href="/"
          className="nav-brand"
          style={{
            display: "flex",
            alignItems: "center",
            gap: 11,
            textDecoration: "none",
            cursor: "none",
          }}
        >
          <LogoMark size={38} />
          <div>
            <div
              style={{
                fontFamily: "'Playfair Display', serif",
                fontSize: 20,
                fontWeight: 700,
                letterSpacing: "-0.02em",
                color: "#09131f",
              }}
            >
              Tawla
            </div>
            <div
              style={{
                fontFamily: "'Noto Sans Arabic', sans-serif",
                fontSize: 13,
                color: "rgba(9, 19, 31, .58)",
                marginTop: -3,
              }}
            >
              طاولة
            </div>
          </div>
        </a>

        <ul
          className="nav-links"
          style={{
            display: "flex",
            alignItems: "center",
            gap: 14,
            listStyle: "none",
            margin: 0,
            padding: 0,
          }}
        >
          {links.map((l) => (
            <li key={l.href}>
              <a
                href={l.href}
                style={{
                  color: "rgba(9, 19, 31, .78)",
                  fontSize: 15,
                  fontWeight: 600,
                  textDecoration: "none",
                  cursor: "none",
                  transition: "all 0.2s",
                  padding: "10px 16px",
                  borderRadius: 999,
                }}
                onMouseEnter={(e) => {
                  e.target.style.color = "#06101d";
                  e.target.style.background = "rgba(255,255,255,.5)";
                }}
                onMouseLeave={(e) => {
                  e.target.style.color = "rgba(9, 19, 31, .78)";
                  e.target.style.background = "transparent";
                }}
              >
                {l.label}
              </a>
            </li>
          ))}
        </ul>

        <div className="nav-actions" style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            className="nav-lang"
            onClick={toggle}
            style={{
              background: "rgba(12, 22, 35, .06)",
              border: "1px solid rgba(9, 19, 31, .12)",
              borderRadius: "var(--r-full)",
              padding: "8px 14px",
              fontSize: 13,
              fontWeight: 600,
              color: "#0b1826",
              cursor: "none",
              transition: "all 0.2s",
              fontFamily: "'DM Sans', sans-serif",
            }}
            onMouseEnter={(e) => {
              e.target.style.background = "rgba(255,255,255,.58)";
              e.target.style.borderColor = "rgba(9, 19, 31, .2)";
            }}
            onMouseLeave={(e) => {
              e.target.style.background = "rgba(12, 22, 35, .06)";
              e.target.style.borderColor = "rgba(9, 19, 31, .12)";
            }}
          >
            {isAr ? "English" : "العربية"}
          </button>
          <a
            href="#demo"
            className="btn-gold nav-cta"
            style={{ padding: "11px 24px", fontSize: 14 }}
          >
            {t("Book Demo →", "احجز عرضاً ←")}
          </a>
        </div>
      </div>
      </div>
    </nav>
  );
}
